var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is the Administration.</color>","TWN":"<color=#ffd34c>以下為管理局正式通知。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這是目前正在發生的真實情況。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 눈보라 현상을 동반한 고위 침식파가 전 세계를 뒤덮고 있습니다.</color>","JPN":"<color=#ffd34c>現在、吹雪を伴う高レベルの侵食波が全世界を覆っています。</color>","ENG":"<color=#ffd34c>The high-grade Corruption ray accompanied by the blizzard is currently covering the world.</color>","TWN":"<color=#ffd34c>目前，一股伴隨暴風雪的高強度侵蝕波正在覆蓋全球。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 절대 눈보라에 노출되지 마시고, 안전한 실내장소로 대피하여 재난 방송을 청취해주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆様は決して外に出ず、室内の安全な場所に退避し、テレビ・ラジオをつけてください。</color>","ENG":"<color=#ffd34c>Citizens are asked to not be exposed to the snow, evacuate to a safe place indoors, and listen to the disaster broadcast.</color>","TWN":"<color=#ffd34c>各位市民，請務必不要暴露在暴風雪中，請前往室內躲避並收聽本災害廣播。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내된 지침은 재난경보 해제까지 유효합니다.</color>","JPN":"<color=#ffd34c>ご案内している行動指針は災難警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The broadcast guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>該指示一直持續到警報解除。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회의 움직임이 포착된 곳은 이 부근입니다.","JPN":"学会の動きを捉えたのは、この辺りです。","ENG":"This is where we detected the movement of the Society.","TWN":"捕捉到學會動靜的地方就在這附近。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 뭐가 보여야 학회 녀석들을 쫓든, 말든 할 거 아니야?","JPN":"ったく。何も見えないのに、どうやってやつらを追いかけろってんだ？","ENG":"Blimey. I can't chase anyone in this weather.","TWN":"真是的，什麼都看不見是要怎麼追？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이렇게 눈보라가 심해서야 또 녀석들을 놓치겠군!","JPN":"この吹雪では、またやつらを逃してしまうぞ！","ENG":"We're going to lose them again in this bad of a snowstorm!","TWN":"暴風雪這麼厲害，說不定又要錯過那傢伙了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배! 이래서는 끝도 없겠어! 흩어져서 찾아보자!","JPN":"ジジイ！　これじゃキリがない！　二手に分かれよう！","ENG":"Old chap! This is pointless! We should split and look for them!","TWN":"老頭！這樣下去可沒完沒了啊！要不分開找找看吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 전에 이거나 받게!","JPN":"その前に、これを受け取れ！","ENG":"Take this first!"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이건? 반지?","JPN":"なんだ、これ？　指輪？","ENG":"What is this? A ring?","TWN":"這是什麼？戒指？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"에이전트 심볼. 기관의 정식 요원에게만 부여되는 인장이자, 요원 장비라네.","JPN":"エージェントシンボル。機関の正式エージェントにだけ与えられる印章であり、エージェントの装備だ。","ENG":"A symbol of an agent. It's a stamp and agent gear, only given to the official agents of the Institution.","TWN":"特工象徵。是僅賦予機關正式特工的印章，也是正式特工的裝備。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"단방향이지만 지금처럼 고위 침식파장 속이나 이면세계에서도 연락 수단으로 쓸 수 있어.","JPN":"一方向だが、今のように高レベル侵食波の中や裏世界でも連絡手段として使える。","ENG":"It can be used as a one-way communication device within high Corruption rays or in the Counterside.","TWN":"雖然是單向的，但是像現在這樣，在高階侵蝕波或異界中也可以作為聯絡手段使用。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 일이 있으면, 즉시 그걸로 호출하게.","JPN":"何かあったら、すぐにそれで呼び出せ。","ENG":"Call me immediately if something happens.","TWN":"有什麼事，就馬上用那個呼叫我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 하여간 이런 게 있었으면 빨랑빨랑 내 놓으란 말이야.","JPN":"チッ、こんなものがあったんならもっと早く出せよ。","ENG":"Tch, took you long enough to hand it over.","TWN":"嘖，既然有這樣的東西，怎麼不早點拿出來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제길, 이렇게 온 세상이 새하얀데 학회 녀석들은 코빼기도 안 보이잖아?","JPN":"くそ、こんなに真っ白なのに、学会のやつらの姿はまったく見えないな。","ENG":"Bollocks, the world is completely white, and I can't see a single Society bloke.","TWN":"可惡，現在一片白，連學會這幫傢伙的影子都看不見。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 녀석들이 진짜 여기 있긴 한 거야?","JPN":"そもそも、本当にやつらはここにいるのか？","ENG":"Are they even here in the first place?","TWN":"他們真的會在這裡？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……이건? 학회 녀석들이 쓰는 저격총 소리.","JPN":"……これは？　学会のやつらが使う狙撃銃の音だ。","ENG":"...Hmm? That's the sound of the sniper rifle that the Society members use.","TWN":"……這是？學會那些傢伙們使用的狙擊槍聲。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"저쪽인가!","JPN":"あっちか！","ENG":"Is it that way?","TWN":"是那邊嗎！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"큭……!?","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"咳……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"미안미안, 눈보라 때문에 사람을 잘못 봤네?","JPN":"ごめんごめん、吹雪で見間違えちゃったよ。","ENG":"Sorry, sorry! Mistook you for another person because of the snowstorm!","TWN":"喔！對不起對不起，因為暴風雪認錯人了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그림자가 보여서 일단 머리 쪽을 쐈는데 빗나갈 줄이야!","JPN":"影が見えたから一応頭を狙って撃ったけど、外しちゃった！","ENG":"I saw a shadow so I went for the head, but I didn't think I'd miss!","TWN":"我看到了影子，本來想往頭上打的，沒想到打偏了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 너는……!","JPN":"待てよ、お前は……！","ENG":"Wait, you're...!","TWN":"等等，你……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그때 감옥에서 봤던 그 망할 토끼녀잖아?","JPN":"あの時牢獄で見たクソウサギ女じゃないか？","ENG":"That damn bunny girl that I saw in prison that day!","TWN":"不就是監獄裡的那個可惡的兔子女嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어라? 날 알아? 이거 영광인걸! ","JPN":"あれ？　アタシのこと知ってるの？　これは光栄だね！ ","ENG":"Huh? You know me? I'm honored!","TWN":"嗯？你認識我嗎？我好榮幸喔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"날 보고 살아서 돌아간 녀석들은 몇 안 되는데 말이야!","JPN":"アタシを見て生きて帰ったやつは貴重なんだよ！","ENG":"Only a few have survived after encountering me!","TWN":"看到我之後能活著回去的傢伙還真沒幾個呢！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"흐으으음…… 근데 감옥에서 날 봤다고?","JPN":"ふむむむ……でも、牢獄でアタシを見た？","ENG":"Hmmm... But you saw me in prison?","TWN":"唔嗯……你說你在監獄裡看到了我？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어디 감옥이었더라……?","JPN":"どこの牢獄だっけ……？","ENG":"Which prison was it...?","TWN":"是哪個監獄來著……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아! 기억났다! 기억났어!","JPN":"あ！　思い出した！　思い出したよ！","ENG":"Oh! I remember! I remember!","TWN":"啊！我想起來了！想起來了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그때 리플레이서 잔당 녀석들 감옥에서 만났던 금발 머리 양아치구나!","JPN":"あの時リプレイサーの残党の牢獄で会った金髪ヤンキー！","ENG":"You're that blonde delinquent that I met at the Replacers remnants' prison!","TWN":"你是在克隆集團餘黨的監獄裡遇到的金毛小混混！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"네 이름이…… 로완 베넷이었나?","JPN":"アンタの名前は確か……ローワン・ベネットだっけ？","ENG":"Your name was... Rowan Benett?","TWN":"你叫……羅萬·班尼特吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷이거든!","JPN":"ロイ・バーネットだ！","ENG":"It's Roy Burnett!","TWN":"是羅伊·伯內特！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};